@startuml
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #f0f0f0
  BorderColor black
  ArrowColor black
}
skinparam stereotype {
  BackgroundColor #a8d8ea
  BorderColor black
  FontColor black
}
skinparam note {
  BackgroundColor #ffcccc
  BorderColor black
}

package "InheritanceDesign" {
  class "Asset" as Asset {
    <<A>>
  }
  class "Security" as Security {
    <<A>>
  }
  class "Property" as Property {
    <<A>>
  }
  class "BankAccount" as BankAccount {
    <<C>>
  }
  class "Bond" as Bond {
    <<C>>
  }
  class "Stock" as Stock {
    <<C>>
  }
  class "Car" as Car {
    <<C>>
  }
  class "House" as House {
    <<C>>
  }
  class "Wealth" as Wealth {
    <<C>>
  }
}

package "java" {
  package "lang" {
    class "@Override" as Override {
      <<@>>
    }
  }
}

Asset <|-- Security
Asset <|-- Property
Asset <|-- BankAccount
Security <|-- Bond
Security <|-- Stock
Property <|-- Car
Property <|-- House
Wealth ..> Override
Bond ..> Override
Stock ..> Override
Car ..> Override
House ..> Override
BankAccount ..> Override

@enduml
